mod atomic_str;
mod backend;
mod cow_str;
mod minify_key;
pub use atomic_str::AtomicStr;
pub use backend::{Backend, BackendExt, CombinedBackend, SimpleBackend};
pub use cow_str::CowStr;
pub use minify_key::{
    minify_key, MinifyKey, DEFAULT_MINIFY_KEY, DEFAULT_MINIFY_KEY_LEN, DEFAULT_MINIFY_KEY_PREFIX,
    DEFAULT_MINIFY_KEY_THRESH,
};

#[cfg(feature = "codegen")]
mod config;
#[cfg(feature = "codegen")]
pub use config::I18nConfig;

pub fn is_debug() -> bool {
    std::env::var("RUST_I18N_DEBUG").unwrap_or_else(|_| "0".to_string()) == "1"
}

#[cfg(feature = "codegen")]
use normpath::PathExt;
#[cfg(feature = "codegen")]
use std::fs::File;
#[cfg(feature = "codegen")]
use std::io::prelude::*;
#[cfg(feature = "codegen")]
use std::{collections::BTreeMap, path::Path};

#[cfg(feature = "codegen")]
type Locale = String;
#[cfg(feature = "codegen")]
type Value = serde_json::Value;
#[cfg(feature = "codegen")]
type Translations = BTreeMap<Locale, Value>;

#[cfg(feature = "codegen")]
fn merge_value(a: &mut Value, b: &Value) {
    match (a, b) {
        (Value::Object(a), Value::Object(b)) => {
            for (k, v) in b {
                merge_value(a.entry(k.clone()).or_insert(Value::Null), v);
            }
        }
        (a, b) => {
            *a = b.clone();
        }
    }
}

#[cfg(feature = "codegen")]
pub fn load_locales<F: Fn(&str) -> bool>(
    locales_path: &str,
    ignore_if: F,
) -> BTreeMap<String, BTreeMap<String, String>> {
    match try_load_locales(locales_path, ignore_if, false) {
        Ok(locales) => locales,
        Err(error) => panic!("{}", error),
    }

